import{_ as t,o as e,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F06: 存貨與債務穩定度審計 - 財務分析專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8074_鉅橡/20260501/F06_存貨與債務穩定度審計_財務分析專家.md","filePath":"審計報告庫/財務審計/8074_鉅橡/20260501/F06_存貨與債務穩定度審計_財務分析專家.md"}'),o={name:"審計報告庫/財務審計/8074_鉅橡/20260501/F06_存貨與債務穩定度審計_財務分析專家.md"};function l(n,a,s,c,h,d){return e(),r("div",null,[...a[0]||(a[0]=[i('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f06-存貨與債務穩定度審計-財務分析專家-審計報告" tabindex="-1">F06: 存貨與債務穩定度審計 - 財務分析專家 審計報告 <a class="header-anchor" href="#f06-存貨與債務穩定度審計-財務分析專家-審計報告" aria-label="Permalink to &quot;F06: 存貨與債務穩定度審計 - 財務分析專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>存貨金額變動趨勢為何？流動性資產是否足以覆蓋短期與長期債務？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：鉅橡存貨由 4.32 億降至 3.76 億，存貨/營收比由 14.8% 降至 11.5%，現金充足。</li><li><strong>風險評級</strong>：中（長債由 0.36 億增至 7.89 億）</li><li><strong>數據時效</strong>：截至 2025 Q4</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>存貨</strong>：2025 Q1=3.99 億 → Q4=3.76 億（-5.8%），存貨/營收比由 14.8% 降至 11.5%，週轉約 3.5x / 104 天。</li><li><strong>債務</strong>：短債由 8.57 億降至 4.85 億，長債由 0.36 億增至 7.89 億，流動比 1.94x、速動比 1.30x。</li><li><strong>診斷</strong>：鉅橡以長債替換短債，降低再融資壓力；Q4 存貨微升屬季節備料。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="【存貨金額變動趨勢】" tabindex="-1">【存貨金額變動趨勢】 <a class="header-anchor" href="#【存貨金額變動趨勢】" aria-label="Permalink to &quot;【存貨金額變動趨勢】&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2025 全年存貨均價約 3.75 億，較 2023 Q1 的 4.32 億下降 16.2%；存貨/營收比由 14.8%（2023 Q1）降至 11.5%（2025 Q4），存貨週轉天數約 104 天。</li><li><strong>深度見解</strong>：存貨佔總資產比由 14.8% 降至 11.5%，顯示鉅橡在 2023-2025 年間持續執行庫存精簡策略。2025 Q4 存貨由 3.62 億微升至 3.76 億（+3.8% QoQ），但同期營收由 343M 降至 325M（-5.3%），存貨/營收比仍由 10.6% 升至 11.5%，僅升 90bp，未達警訊門檻。此微幅上升更可能反映年末備料或訂單交收時點差異，而非產品滯銷。</li></ul><h3 id="【流動性覆蓋短期債務】" tabindex="-1">【流動性覆蓋短期債務】 <a class="header-anchor" href="#【流動性覆蓋短期債務】" aria-label="Permalink to &quot;【流動性覆蓋短期債務】&quot;">​</a></h3><ul><li><strong>核心重點</strong>：現金及約當現金 6.18 億（2025 Q4），短期借款 4.85 億，現金/短債比 1.27x；流動資產 15.32 億 / 流動負債 7.91 億 = 流動比率 1.94x；速動資產（現金+應收帳款）/ 流動負債 = 1.30x。</li><li><strong>深度見解</strong>：現金覆蓋短債比 &gt; 1.0，流動比率近 2x，速動比率 1.3x，三項指標均遠離「流動性斷鏈」警戒線（&lt; 1.0）。鉅橡的流動性緩衝充足，短期償債壓力可控。</li></ul><h3 id="【長期債務結構變化】" tabindex="-1">【長期債務結構變化】 <a class="header-anchor" href="#【長期債務結構變化】" aria-label="Permalink to &quot;【長期債務結構變化】&quot;">​</a></h3><ul><li><strong>核心重點</strong>：長期借款由 2023 Q1 的 0.36 億暴增至 2025 Q4 的 7.89 億（+2,092%），總負債由 14.15 億升至 15.80 億，總負債/權益比由 48.5% 升至 47.9%（因權益同步成長，實際比率穩定）。</li><li><strong>深度見解</strong>：鉅橡正執行「短債換長債」的結構性調整——以 7.53 億長期借款替換 3.72 億短期借款，總負債規模僅增加 1.65 億（+11.7%），但再融資風險大幅降低。長期借款佔總資產比由 0.12% 升至 24.1%，需關注利息負擔對淨利的侵蝕。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一：長期借款暴增的利息負擔壓力測試</strong>——鉅橡長期借款由 0.36 億增至 7.89 億，若以保守利率 1.5% 估算，年利息支出約 0.12 億。以 2025 全年淨利約 1.13 億（四季加總）計算，利息覆蓋倍數約 9.4x，目前仍在安全範圍；但若利率環境惡化或營收放緩，利息負擔將快速侵蝕獲利空間。</li><li><strong>空頭風險二：Q4 存貨回升的季節性 vs. 結構性疑雲</strong>——2025 Q4 存貨由 Q3 的 3.62 億升至 3.76 億，同時營收由 Q3 的 343M 降至 325M（-5.3%），存貨/營收比由 10.6% 升至 11.5%。若此趨勢延續至 2026 Q1，存貨週轉天數可能突破 110 天，疊加下游需求放緩，將觸發跌價損失提列的實質風險。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK — <code>TaiwanStockBalanceSheet</code> + <code>TaiwanStockFinance</code></li><li><strong>查詢參數</strong>：stock_id=8074, start=2023-01-01, end=2026-05-01</li><li><strong>關鍵核對碼</strong>：Inventories=375,790K (2025 Q4), ShorttermBorrowings=485,118K (2025 Q4), LongtermBorrowings=788,875K (2025 Q4), CurrentLiabilities=791,205K (2025 Q4)</li><li><strong>年報/法說</strong>: 本地 PDF 資料庫不可用（節點未連線），以 FinMind 季報數據為唯一來源</li></ul>',19)])])}const g=t(o,[["render",l]]);export{u as __pageData,g as default};
